import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"压倒性的气势","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/0.无支线/压倒性的气势.md","filePath":"4.资源分区/7.物品与装备/4.奇物/0.无支线/压倒性的气势.md"}'),p={name:"4.资源分区/7.物品与装备/4.奇物/0.无支线/压倒性的气势.md"};function d(_,a,l,i,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"压倒性的气势",tabindex:"-1"},[s("压倒性的气势 "),e("a",{class:"header-anchor",href:"#压倒性的气势","aria-label":'Permalink to "压倒性的气势"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌037")])])],-1),o('<h1 id="压倒性的气势-1" tabindex="-1">压倒性的气势 <a class="header-anchor" href="#压倒性的气势-1" aria-label="Permalink to &quot;压倒性的气势&quot;">​</a></h1><p>压倒性的气势<br> 奇物（披风）<br> 魔幻本质<br> 价格：1000<br> 描述：看似普通且破旧的红色披风，也许他……并不普通？<br> 效果：</p><p>【英雄的象征】：当你拿到这个披风的瞬间，你仿佛可以看到无数名前辈挡在众人身前的无畏的身影，他们身形不一，容貌各异，但是无一例外，都带着某种决绝，这是一种源于命运的坚持，这更是一种决不退缩的勇气，而这更是一种源于英雄的象征！！当你披上这个披风，你将继承那无数的身影，他们都将成为你的力量，将你推向高处，每当进入影片，你都会成为那个世界中最不起眼的那一份子，成为最普通的那一类人，但是时刻记住！英雄可以从任何地方出现！！！<br> 这视为披风将提供无支线幻象来源的背景身份（没有实际效果），但是你除了身份和披风一无所有。</p><p>【英雄不倒】：信念，是每一位英雄由内而外散发出来的气场，坚持，是每一位英雄所赞颂的品格，而你！我的朋友，当你披上这个披风的那一瞬间，信念与坚持就早已降临在你的身上，当你为保护他人而受伤时，你可以强忍疼痛，说出没关系：当你感动得痛哭流涕时，你可以忍住抽泣，说出没关系：当你因为遭受他人背叛，而心痛时，你可以捂住自己内心的裂痕，说出没关系……是啊！正是一次次地把苦痛独自吞下，正是一次次的站起身姿，才能成为真正的英雄吧！所以，无需担心丢人，你可以在任何时刻都说出【没关系】这个词，并且伪装出什么事也没有的表情，因为，英雄不到！<br> 这视为一种无支线的伪装（没有实际效果），无需观察，是一个智慧生物都能看出你真实的情感。</p><p>【搞笑角色】：笑容与悲伤之间，英雄，会选择什么？这是一个多选题，也是一个必选题，但是如果能让别人笑口常开，那么为什么不呢？玩偶英雄将自己的棉花给予他人，狐狸英雄将智慧赠与他人，那么英雄你呢？我想……你拥有你自己，你可以在任何时刻面带笑容，发出搞怪的音效将大家逗笑，什么小丑！这叫搞笑角色！！<br> 这视为无支线的信息共享，你将你的快乐，哪怕是表层的快乐，传递给了对方，让对方知道有这么一回事。</p><p>【压倒性的气势】：我不愿为此妥协！我将抗争到底！你可以将你的内心所想全盘托出，哪怕只是最微不足道的“想吃饱饭”，这也会令你拥有压倒性的气势，堂吉诃德怎么了！他是一位真正的勇士！我若是我真的有朝一日能够成为英雄！哪怕付出一切，那我也在所不惜。<br> 你的决心相关检定获得1点士气加值。</p><p>【英雄的重担】：你在挑选自己心怡的资源，而披风也在挑选着自己真正的主人，当你买下它的一瞬间似乎有一个灵魂般的重量压在了你的身上，当你回头望去，原来是披风紧紧的拥抱住了你，他将永远地陪伴着你，倾听你的所有苦衷，包容你的所有脆弱，英雄不是这么好当的，强忍着不落泪的感觉一定不好受，在别人面前当小丑也一定令你身心俱疲，没关系，你去拯救世界吧，我会陪着你<br> 你可以给你的披风买一个【萌化】，这样当只有你和披风独自相处时，它会变成有温度的玩偶，伴你左右，陪你入眠，但这并并不会带来任何实际效果。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=r(p,[["render",d]]);export{f as __pageData,m as default};
